static MemInode g_inodes[MAX_INODES_LOCAL + 1];
static OpenFile g_fds[MAX_OPEN_FILES];
static int g_initialized = 0;
static int g_cwd = ROOTINODE;

static void init_fs(void);
static int alloc_inode(int type, int parent_inum);
static void release_inode_if_unlinked(int inum);
static int split_path(const char *path, char comps[][DIRNAMELEN + 1], int *count, int *is_abs);
static int resolve_path_internal(const char *path, int base_cwd, int follow_last, int depth, int *out_inum);
static int resolve_path(const char *path, int follow_last, int *out_inum);
static int resolve_parent(const char *path, int *parent_inum, char out_name[DIRNAMELEN + 1]);
static int find_slot(int dir_inum, const char *name);
