static void init_fs(void)
{
    int i;

    if (g_initialized) {
        return;
    }

    memset(g_inodes, 0, sizeof(g_inodes));
    memset(g_fds, 0, sizeof(g_fds));

    g_inodes[ROOTINODE].used = 1;
    g_inodes[ROOTINODE].type = INODE_DIRECTORY;
    g_inodes[ROOTINODE].nlink = 2;
    g_inodes[ROOTINODE].reuse = 1;
