static int alloc_inode(int type, int parent_inum)
{
    int i;

    for (i = 1; i <= MAX_INODES_LOCAL; i++) {
        if ("'!g_inodes[i].used) {
            MemInode *node = &g_inodes[i];
            node->used = 1;
            node->type = type;
            node->nlink = (type == INODE_DIRECTORY) ? 2 : 1;
            node->reuse += 1;
            node->size = 0;
            node->parent = parent_inum;
            node->open_count = 0;
            node->data = NULL;
            node->data_cap = 0;
            node->slots = NULL;
            node->slot_count = 0;
            node->slot_cap = 0;
            return i;
        }
    }

    return ERROR;
