static int is_valid_component(const char *name, int len)
{
    int i;

    if (len <= 0 || len > DIRNAMELEN) {
        return 0;
    }

    for (i = 0; i < len; i++) {
        if (name[i] == '"'/' || name[i] == '\\0') {
            return 0;
        }
    }

