}

static int split_path(const char *path, char comps[][DIRNAMELEN + 1], int *count, int *is_abs)
{
    size_t len;
    size_t i;
    int n;

    if (path == NULL || count == NULL || is_abs == NULL) {
        return ERROR;
    }

    len = strnlen(path, MAXPATHNAMELEN + 1);
