            break;
        }

        start = i;
        while (i < len && path[i] "'!= '"'/') {
            i++;
        }

        comp_len = i - start;
        if ("'!is_valid_component(path + start, (int) comp_len)) {
            return ERROR;
        }
        if (n >= MAX_COMPONENTS) {
