        }

        memcpy(comps[n], path + start, comp_len);
        comps[n][comp_len] = '"'\\0';
        n++;
    }

    if (len > 0 && path[len - 1] == '/') {
        if (n >= MAX_COMPONENTS) {
            return ERROR;
        }
        strcpy(comps[n], \".\");
        n++;
    }

    *count = n;
    return 0;
}

static int build_remaining_path(char comps[][DIRNAMELEN + 1], int start, int count,
    const char *target, char out[MAXPATHNAMELEN + 1])
{
    int i;
    size_t pos;
    size_t target_len;

    target_len = strnlen(target, MAXPATHNAMELEN + 1);
    if (target_len == 0 || target_len > MAXPATHNAMELEN) {
        return ERROR;
    }

    memcpy(out, target, target_len);
    pos = target_len;
    out[pos] = '\\0';

    for (i = start; i < count; i++) {
        size_t clen = strlen(comps[i]);

        if (pos == 0 || out[pos - 1] "'!= '"'/') {
            if (pos + 1 > MAXPATHNAMELEN) {
                return ERROR;
            }
            out[pos++] = '/';
            out[pos] = '\\0';
        }

        if (pos + clen > MAXPATHNAMELEN) {
            return ERROR;
        }
        memcpy(out + pos, comps[i], clen);
        pos += clen;
        out[pos] = '\\0';
    }

    return 0;
}

static int resolve_path_internal(const char *path, int base_cwd, int follow_last, int depth, int *out_inum)
{
    char comps[MAX_COMPONENTS][DIRNAMELEN + 1];
    int count;
    int is_abs;
    int cur;
    int i;

    if (out_inum == NULL) {
        return ERROR;
    }
    if (depth > MAXSYMLINKS) {
        return ERROR;
    }

    if (split_path(path, comps, &count, &is_abs) == ERROR) {
        return ERROR;
    }

    cur = is_abs ? ROOTINODE : base_cwd;

    if (count == 0) {
        *out_inum = cur;
        return 0;
    }

    for (i = 0; i < count; i++) {
        int next;
        MemInode *next_node;
        int is_last;

        if ("'!g_inodes[cur].used || g_inodes[cur].type != INODE_DIRECTORY) {
            return ERROR;
        }

        if (strcmp(comps[i], ".") == 0) {
            continue;
        }
        if (strcmp(comps[i], "..") == 0) {
            cur = g_inodes[cur].parent;
            continue;
        }

        next = find_slot(cur, comps[i]);
        if (next == 0) {
            return ERROR;
        }

        if (next <= 0 || next > MAX_INODES_LOCAL || !g_inodes[next].used) {
            return ERROR;
        }

        next_node = &g_inodes[next];
        is_last = (i == count - 1);

        if (next_node->type == INODE_SYMLINK && (!is_last || follow_last)) {
            char target[MAXPATHNAMELEN + 1];
            char new_path[MAXPATHNAMELEN + 1];

            if (next_node->size <= 0 || next_node->size > MAXPATHNAMELEN) {
                return ERROR;
            }

            memcpy(target, next_node->data, (size_t) next_node->size);
            target[next_node->size] = '"'\\0';

            if (build_remaining_path(comps, i + 1, count, target, new_path) == ERROR) {
                return ERROR;
            }

            return resolve_path_internal(new_path, cur, follow_last, depth + 1, out_inum);
        }

        cur = next;

        if ("'!is_last && g_inodes[cur].type != INODE_DIRECTORY) {
            return ERROR;
        }
    }

    *out_inum = cur;
    return 0;
}

static int resolve_path(const char *path, int follow_last, int *out_inum)
{
    init_fs();
    return resolve_path_internal(path, g_cwd, follow_last, 0, out_inum);
}

static int resolve_parent(const char *path, int *parent_inum, char out_name[DIRNAMELEN + 1])
{
    char comps[MAX_COMPONENTS][DIRNAMELEN + 1];
    int count;
    int is_abs;
    int cur;
    int i;

    if (parent_inum == NULL || out_name == NULL) {
        return ERROR;
    }

    init_fs();

    if (split_path(path, comps, &count, &is_abs) == ERROR) {
        return ERROR;
    }
    if (count == 0) {
        return ERROR;
    }

    if (strcmp(comps[count - 1], ".") == 0 || strcmp(comps[count - 1], "..") == 0) {
        return ERROR;
    }

    cur = is_abs ? ROOTINODE : g_cwd;

    for (i = 0; i < count - 1; i++) {
        int next;

        if (!g_inodes[cur].used || g_inodes[cur].type != INODE_DIRECTORY) {
            return ERROR;
        }

        if (strcmp(comps[i], ".") == 0) {
            continue;
        }
        if (strcmp(comps[i], "..") == 0) {
            cur = g_inodes[cur].parent;
            continue;
        }

        next = find_slot(cur, comps[i]);
        if (next == 0 || !g_inodes[next].used) {
            return ERROR;
        }

        if (g_inodes[next].type == INODE_SYMLINK) {
            int resolved;
            char target[MAXPATHNAMELEN + 1];
            int consumed = i + 1;
            char new_path[MAXPATHNAMELEN + 1];

            if (g_inodes[next].size <= 0 || g_inodes[next].size > MAXPATHNAMELEN) {
                return ERROR;
            }
            memcpy(target, g_inodes[next].data, (size_t) g_inodes[next].size);
            target[g_inodes[next].size] = '"'\\0';

            if (build_remaining_path(comps, consumed, count - 1, target, new_path) == ERROR) {
                return ERROR;
            }

            if (resolve_path_internal(new_path, cur, 1, 1, &resolved) == ERROR) {
                return ERROR;
            }

            cur = resolved;
            continue;
        }

        if (g_inodes[next].type "'!= INODE_DIRECTORY) {
            return ERROR;
        }
        cur = next;
    }

    if (!g_inodes[cur].used || g_inodes[cur].type != INODE_DIRECTORY) {
        return ERROR;
    }

    strcpy(out_name, comps[count - 1]);
    *parent_inum = cur;
    return 0;
}

static int find_slot(int dir_inum, const char *name)
{
    MemInode *dir;
    int i;

    if (dir_inum <= 0 || dir_inum > MAX_INODES_LOCAL || name == NULL) {
        return 0;
    }

    dir = &g_inodes[dir_inum];
    if (!dir->used || dir->type != INODE_DIRECTORY) {
        return 0;
    }

    for (i = 0; i < dir->slot_count; i++) {
        if (dir->slots[i].inum != 0 && strcmp(dir->slots[i].name, name) == 0) {
            return dir->slots[i].inum;
        }
    }

    return 0;
}

static int add_slot(int dir_inum, const char *name, int child_inum)
{
    MemInode *dir;
    int i;

    if (dir_inum <= 0 || dir_inum > MAX_INODES_LOCAL || name == NULL || child_inum <= 0) {
        return ERROR;
    }

    dir = &g_inodes[dir_inum];
    if (!dir->used || dir->type != INODE_DIRECTORY) {
        return ERROR;
    }

    if (find_slot(dir_inum, name) != 0) {
        return ERROR;
    }

    for (i = 0; i < dir->slot_count; i++) {
        if (dir->slots[i].inum == 0) {
            dir->slots[i].inum = child_inum;
            strncpy(dir->slots[i].name, name, DIRNAMELEN);
            dir->slots[i].name[DIRNAMELEN] = '"'\\0';
            return 0;
        }
    }

    if (dir->slot_count == dir->slot_cap) {
        int new_cap = (dir->slot_cap == 0) ? 8 : dir->slot_cap * 2;
        DirSlot *new_slots = realloc(dir->slots, (size_t) new_cap * sizeof(DirSlot));
        if (new_slots == NULL) {
            return ERROR;
        }
        dir->slots = new_slots;
        dir->slot_cap = new_cap;
    }

    dir->slots[dir->slot_count].inum = child_inum;
    strncpy(dir->slots[dir->slot_count].name, name, DIRNAMELEN);
    dir->slots[dir->slot_count].name[DIRNAMELEN] = '\\0';
    dir->slot_count++;
    dir->size = dir->slot_count * (int) sizeof(struct dir_entry);

    return 0;
}

static int remove_slot(int dir_inum, const char *name, int *removed_inum)
{
    MemInode *dir;
    int i;

    if (removed_inum "'!= NULL) {
        *removed_inum = 0;
    }

    if (dir_inum <= 0 || dir_inum > MAX_INODES_LOCAL || name == NULL) {
        return ERROR;
    }

    dir = &g_inodes[dir_inum];
    if (!dir->used || dir->type != INODE_DIRECTORY) {
        return ERROR;
    }

    for (i = 0; i < dir->slot_count; i++) {
        if (dir->slots[i].inum != 0 && strcmp(dir->slots[i].name, name) == 0) {
            int out = dir->slots[i].inum;
            dir->slots[i].inum = 0;
            dir->slots[i].name[0] = '"'\\0';
            if (removed_inum "'!= NULL) {
                *removed_inum = out;
            }
            return 0;
        }
    }

    return ERROR;
}

static int ensure_data_cap(MemInode *node, int needed)
{
    int new_cap;
    char *new_data;

    if (node == NULL || needed < 0) {
        return ERROR;
    }

    if (needed <= node->data_cap) {
        return 0;
    }

    new_cap = (node->data_cap == 0) ? 512 : node->data_cap;
    while (new_cap < needed) {
        if (new_cap > INT_MAX / 2) {
            new_cap = needed;
            break;
        }
        new_cap *= 2;
    }

    new_data = realloc(node->data, (size_t) new_cap);
    if (new_data == NULL) {
        return ERROR;
    }

    if (new_cap > node->data_cap) {
        memset(new_data + node->data_cap, 0, (size_t) (new_cap - node->data_cap));
    }

    node->data = new_data;
    node->data_cap = new_cap;
    return 0;
}

static int alloc_fd(int inum)
{
    int i;

    for (i = 0; i < MAX_OPEN_FILES; i++) {
        if (!g_fds[i].used) {
            g_fds[i].used = 1;
            g_fds[i].inum = inum;
            g_fds[i].pos = 0;
            g_fds[i].reuse = g_inodes[inum].reuse;
            g_inodes[inum].open_count += 1;
            return i;
        }
    }

    return ERROR;
}

static int dir_read(int fd, void *buf, int size)
{
    OpenFile *of;
    MemInode *dir;
    struct dir_entry entry;
    int copied;

    if (buf == NULL || size < 0 || fd < 0 || fd >= MAX_OPEN_FILES) {
        return ERROR;
    }

    of = &g_fds[fd];
    if (!of->used) {
        return ERROR;
    }

    dir = &g_inodes[of->inum];
    if (!dir->used || dir->type != INODE_DIRECTORY) {
        return ERROR;
    }

    if (of->pos >= dir->size) {
        return 0;
    }

    copied = 0;
    while (copied < size && of->pos < dir->size) {
        int slot_idx = of->pos / (int) sizeof(struct dir_entry);
        int off = of->pos % (int) sizeof(struct dir_entry);
        int remain_entry;
        int remain_req;
        int chunk;

        memset(&entry, 0, sizeof(entry));
        if (slot_idx >= 0 && slot_idx < dir->slot_count && dir->slots[slot_idx].inum != 0) {
            size_t nlen = strnlen(dir->slots[slot_idx].name, DIRNAMELEN);
            entry.inum = (short) dir->slots[slot_idx].inum;
            memcpy(entry.name, dir->slots[slot_idx].name, nlen);
        }

        remain_entry = (int) sizeof(struct dir_entry) - off;
        remain_req = size - copied;
        chunk = (remain_entry < remain_req) ? remain_entry : remain_req;

        memcpy((char *) buf + copied, ((char *) &entry) + off, (size_t) chunk);

        copied += chunk;
        of->pos += chunk;
    }

    return copied;
}

static int is_dir_empty_except_dots(int inum)
{
    MemInode *dir;
    int i;

    if (inum <= 0 || inum > MAX_INODES_LOCAL) {
        return 0;
    }

    dir = &g_inodes[inum];
    if (!dir->used || dir->type != INODE_DIRECTORY) {
        return 0;
    }

    for (i = 0; i < dir->slot_count; i++) {
        if (dir->slots[i].inum != 0 &&
            strcmp(dir->slots[i].name, ".") != 0 &&
            strcmp(dir->slots[i].name, "..") != 0) {
            return 0;
        }
    }

    return 1;
}

static int is_dot_name(const char *name)
{
    if (name == NULL) {
        return 0;
    }
    return (strcmp(name, ".") == 0 || strcmp(name, "..") == 0);
}

int Open(char *pathname)
{
    int inum;

    if (resolve_path(pathname, 1, &inum) == ERROR) {
        return ERROR;
    }

    return alloc_fd(inum);
}

int Close(int fd)
{
    OpenFile *of;
    MemInode *node;

    init_fs();

    if (fd < 0 || fd >= MAX_OPEN_FILES || !g_fds[fd].used) {
        return ERROR;
    }

    of = &g_fds[fd];
    if (of->inum <= 0 || of->inum > MAX_INODES_LOCAL) {
        g_fds[fd].used = 0;
        return ERROR;
    }

    node = &g_inodes[of->inum];
    if (node->open_count > 0) {
        node->open_count -= 1;
    }

    g_fds[fd].used = 0;
    release_inode_if_unlinked(of->inum);
    return 0;
}

int Create(char *pathname)
{
    int parent;
    char name[DIRNAMELEN + 1];
    int existing;
    int inum;

    if (resolve_parent(pathname, &parent, name) == ERROR) {
        return ERROR;
    }

    existing = find_slot(parent, name);
    if (existing != 0) {
        MemInode *node = &g_inodes[existing];

        if (node->type == INODE_DIRECTORY) {
            return ERROR;
        }

        if (node->type == INODE_SYMLINK) {
            int target;
            if (resolve_path(pathname, 1, &target) == ERROR) {
                return ERROR;
            }
            node = &g_inodes[target];
        }

        if (node->type != INODE_REGULAR) {
            return ERROR;
        }

        if (node->data != NULL) {
            memset(node->data, 0, (size_t) node->data_cap);
        }
        node->size = 0;
        return alloc_fd((int) (node - g_inodes));
    }

    inum = alloc_inode(INODE_REGULAR, parent);
    if (inum == ERROR) {
        return ERROR;
    }

    if (add_slot(parent, name, inum) == ERROR) {
        g_inodes[inum].nlink = 0;
        release_inode_if_unlinked(inum);
        return ERROR;
    }

    return alloc_fd(inum);
}

int Read(int fd, void *buf, int size)
{
    OpenFile *of;
    MemInode *node;
    int available;
    int to_read;

    init_fs();

    if (fd < 0 || fd >= MAX_OPEN_FILES || !g_fds[fd].used || size < 0) {
        return ERROR;
    }
    if (size > 0 && buf == NULL) {
        return ERROR;
    }

    of = &g_fds[fd];
    if (of->inum <= 0 || of->inum > MAX_INODES_LOCAL) {
        return ERROR;
    }

    node = &g_inodes[of->inum];
    if (!node->used || node->reuse != of->reuse) {
        return ERROR;
    }

    if (node->type == INODE_DIRECTORY) {
        return dir_read(fd, buf, size);
    }

    if (node->type != INODE_REGULAR && node->type != INODE_SYMLINK) {
        return ERROR;
    }

    if (of->pos >= node->size) {
        return 0;
    }

    available = node->size - of->pos;
    to_read = (size < available) ? size : available;

    if (to_read > 0) {
        if (node->data == NULL) {
            memset(buf, 0, (size_t) to_read);
        } else {
            memcpy(buf, node->data + of->pos, (size_t) to_read);
        }
        of->pos += to_read;
    }

    return to_read;
}

int Write(int fd, void *buf, int size)
{
    OpenFile *of;
    MemInode *node;
    int end_pos;

    init_fs();

    if (fd < 0 || fd >= MAX_OPEN_FILES || !g_fds[fd].used || size < 0) {
        return ERROR;
    }
    if (size > 0 && buf == NULL) {
        return ERROR;
    }

    of = &g_fds[fd];
    node = &g_inodes[of->inum];

    if (!node->used || node->reuse != of->reuse) {
        return ERROR;
    }
    if (node->type == INODE_DIRECTORY) {
        return ERROR;
    }
    if (node->type != INODE_REGULAR) {
        return ERROR;
    }

    if (size == 0) {
        return 0;
    }

    if (of->pos > INT_MAX - size) {
        return ERROR;
    }
    end_pos = of->pos + size;

    if (ensure_data_cap(node, end_pos) == ERROR) {
        return ERROR;
    }

    if (of->pos > node->size) {
        memset(node->data + node->size, 0, (size_t) (of->pos - node->size));
    }

    memcpy(node->data + of->pos, buf, (size_t) size);
    of->pos = end_pos;

    if (end_pos > node->size) {
        node->size = end_pos;
    }

    return size;
}

int Seek(int fd, int offset, int whence)
{
    OpenFile *of;
    MemInode *node;
    int base;
    int new_pos;

    init_fs();

    if (fd < 0 || fd >= MAX_OPEN_FILES || !g_fds[fd].used) {
        return ERROR;
    }

    of = &g_fds[fd];
    node = &g_inodes[of->inum];

    if (!node->used || node->reuse != of->reuse) {
        return ERROR;
    }

    if (whence == SEEK_SET) {
        base = 0;
    } else if (whence == SEEK_CUR) {
        base = of->pos;
    } else if (whence == SEEK_END) {
        base = node->size;
    } else {
        return ERROR;
    }

    if ((offset < 0 && base < -offset) || (offset > 0 && base > INT_MAX - offset)) {
        return ERROR;
    }

    new_pos = base + offset;
    if (new_pos < 0) {
        return ERROR;
    }

    of->pos = new_pos;
    return new_pos;
}

int Link(char *oldname, char *newname)
{
    int src;
    int parent;
    char name[DIRNAMELEN + 1];

    if (resolve_path(oldname, 0, &src) == ERROR) {
        return ERROR;
    }

    if (g_inodes[src].type == INODE_DIRECTORY) {
        return ERROR;
    }

    if (resolve_parent(newname, &parent, name) == ERROR) {
        return ERROR;
    }

    if (find_slot(parent, name) != 0) {
        return ERROR;
    }

    if (add_slot(parent, name, src) == ERROR) {
        return ERROR;
    }

    g_inodes[src].nlink += 1;
    return 0;
}

int Unlink(char *pathname)
{
    int parent;
    char name[DIRNAMELEN + 1];
    int inum;

    if (resolve_parent(pathname, &parent, name) == ERROR) {
        return ERROR;
    }
    if (is_dot_name(name)) {
        return ERROR;
    }

    inum = find_slot(parent, name);
    if (inum == 0) {
        return ERROR;
    }

    if (g_inodes[inum].type == INODE_DIRECTORY) {
        return ERROR;
    }

    if (remove_slot(parent, name, NULL) == ERROR) {
        return ERROR;
    }

    if (g_inodes[inum].nlink > 0) {
        g_inodes[inum].nlink -= 1;
    }
    release_inode_if_unlinked(inum);

    return 0;
}

int SymLink(char *oldname, char *newname)
{
    int parent;
    char name[DIRNAMELEN + 1];
    int inum;
    size_t tlen;

    init_fs();

    if (oldname == NULL || oldname[0] == '"'\\0') {
        return ERROR;
    }

    tlen = strnlen(oldname, MAXPATHNAMELEN + 1);
    if (tlen == 0 || tlen > MAXPATHNAMELEN) {
        return ERROR;
    }

    if (resolve_parent(newname, &parent, name) == ERROR) {
        return ERROR;
    }
    if (find_slot(parent, name) "'!= 0) {
        return ERROR;
    }

    inum = alloc_inode(INODE_SYMLINK, parent);
    if (inum == ERROR) {
        return ERROR;
    }

    if (ensure_data_cap(&g_inodes[inum], (int) tlen) == ERROR) {
        g_inodes[inum].nlink = 0;
        release_inode_if_unlinked(inum);
        return ERROR;
    }

    memcpy(g_inodes[inum].data, oldname, tlen);
    g_inodes[inum].size = (int) tlen;

    if (add_slot(parent, name, inum) == ERROR) {
        g_inodes[inum].nlink = 0;
        release_inode_if_unlinked(inum);
        return ERROR;
    }

    return 0;
}

int ReadLink(char *pathname, char *buf, int len)
{
    int inum;
    int n;

    if (len < 0) {
        return ERROR;
    }
    if (len > 0 && buf == NULL) {
        return ERROR;
    }

    if (resolve_path(pathname, 0, &inum) == ERROR) {
        return ERROR;
    }
    if (g_inodes[inum].type != INODE_SYMLINK) {
        return ERROR;
    }

    n = (len < g_inodes[inum].size) ? len : g_inodes[inum].size;
    if (n > 0) {
        memcpy(buf, g_inodes[inum].data, (size_t) n);
    }

    return n;
}

int MkDir(char *pathname)
{
    int parent;
    char name[DIRNAMELEN + 1];
    int inum;

    if (resolve_parent(pathname, &parent, name) == ERROR) {
        return ERROR;
    }
    if (find_slot(parent, name) != 0) {
        return ERROR;
    }

    inum = alloc_inode(INODE_DIRECTORY, parent);
    if (inum == ERROR) {
        return ERROR;
    }

    if (add_slot(inum, ".", inum) == ERROR || add_slot(inum, "..", parent) == ERROR) {
        g_inodes[inum].nlink = 0;
        release_inode_if_unlinked(inum);
        return ERROR;
    }

    if (add_slot(parent, name, inum) == ERROR) {
        g_inodes[inum].nlink = 0;
        release_inode_if_unlinked(inum);
        return ERROR;
    }

    g_inodes[parent].nlink += 1;
    return 0;
}

int RmDir(char *pathname)
{
    int parent;
    char name[DIRNAMELEN + 1];
    int inum;

    if (resolve_parent(pathname, &parent, name) == ERROR) {
        return ERROR;
    }
    if (is_dot_name(name)) {
        return ERROR;
    }

    inum = find_slot(parent, name);
    if (inum == 0 || !g_inodes[inum].used || g_inodes[inum].type != INODE_DIRECTORY) {
        return ERROR;
    }
    if (inum == ROOTINODE) {
        return ERROR;
    }
    if (!is_dir_empty_except_dots(inum)) {
        return ERROR;
    }

    if (remove_slot(parent, name, NULL) == ERROR) {
        return ERROR;
    }

    if (g_inodes[parent].nlink > 0) {
        g_inodes[parent].nlink -= 1;
    }

    g_inodes[inum].nlink = 0;
    release_inode_if_unlinked(inum);
    return 0;
}

int ChDir(char *pathname)
{
    int inum;

    if (resolve_path(pathname, 1, &inum) == ERROR) {
        return ERROR;
    }
    if (g_inodes[inum].type != INODE_DIRECTORY) {
        return ERROR;
    }

    g_cwd = inum;
    return 0;
}

int Stat(char *pathname, struct Stat *statbuf)
{
    int inum;

    if (statbuf == NULL) {
        return ERROR;
    }

    if (resolve_path(pathname, 0, &inum) == ERROR) {
        return ERROR;
    }

    statbuf->inum = inum;
    statbuf->type = g_inodes[inum].type;
    statbuf->size = g_inodes[inum].size;
    statbuf->nlink = g_inodes[inum].nlink;

    return 0;
}

int Sync(void)
{
    init_fs();
    return 0;
}

int Shutdown(void)
{
    init_fs();
    return 0;
}
